local jwt = require "resty.jwt"

-- Define an array of allowed roles for each endpoint
local endpoints = {
  ["/"] = {"user"},
  ["/admin"] = {"admin"},
  ["/api"] = {"api_user"}
}

-- Function to check if a user has the required role for a given endpoint
function check_role(endpoint, token)
  -- Get the list of allowed roles for this endpoint from the endpoints table
  local allowed_roles = endpoints[endpoint]

  -- Check if the token is valid and contains one of the allowed roles
  local valid, err = jwt:verify(token)
  if not valid then
    ngx.log(ngx.ERR, "Invalid JWT token: " .. err)
    return false
  end

  -- Get the role from the token
  local role = valid["role"]

  -- Check if the role is in the list of allowed roles for this endpoint
  for _, allowed_role in ipairs(allowed_roles) do
    if role == allowed_role then
      return true
    end
  end

  ngx.log(ngx.ERR, "User does not have required role for endpoint: " .. endpoint)
  return false
end

